// ============================================================
// FILTER BATCH TASKS + INIT BUDGET
// ============================================================
// Filtre les tâches batch en statut 'À faire'
// Initialise le compteur de budget nuit
// ============================================================

const items = $input.all();
const batchTasks = [];

for (const item of items) {
  const props = item.json.properties || item.json;

  // Extraire le statut
  let statut = '';
  if (props.Statut?.select?.name) statut = props.Statut.select.name;
  else if (props.Statut?.status?.name) statut = props.Statut.status.name;

  // Extraire les tags
  let tags = [];
  if (props.Tags?.multi_select) tags = props.Tags.multi_select.map(t => t.name.toLowerCase());

  // Filtrer : batch + À faire
  if (tags.includes('batch') && statut === '📋 À faire') {
    // Extraire les propriétés utiles
    let nom = 'Sans titre';
    if (props.Nom?.title) nom = props.Nom.title.map(t => t.plain_text).join('');
    else if (props.Name?.title) nom = props.Name.title.map(t => t.plain_text).join('');

    let batchType = 'Contenu';
    if (props.Batch_Type?.select?.name) batchType = props.Batch_Type.select.name;

    let projetCible = '';
    if (props.Projet_Cible?.select?.name) projetCible = props.Projet_Cible.select.name;

    let priorite = 'Moyenne';
    if (props.Priorité?.select?.name) priorite = props.Priorité.select.name;
    // Alternative sans accent
    if (props.Priorite?.select?.name) priorite = props.Priorite.select.name;

    batchTasks.push({
      json: {
        pageId: item.json.id,
        nom,
        batchType,
        projetCible,
        priorite,
        url: item.json.url || ''
      }
    });
  }
}

// Trier par priorité (Haute > Moyenne > Basse)
const prioOrder = { 'Haute': 0, 'Moyenne': 1, 'Basse': 2 };
batchTasks.sort((a, b) => (prioOrder[a.json.priorite] || 1) - (prioOrder[b.json.priorite] || 1));

// Init budget dans static data
const staticData = $getWorkflowStaticData('global');
staticData.night_budget = 0;
staticData.night_results = [];
staticData.night_start = new Date().toISOString();

if (batchTasks.length === 0) {
  return [{ json: { empty: true, count: 0 } }];
}

return batchTasks;

// ============================================================
// CHECK BUDGET + PREPARE TASK
// ============================================================
const staticData = $getWorkflowStaticData('global');
const budget = staticData.night_budget || 0;
const BUDGET_MAX = 0.30;

const item = $input.first().json;

if (budget >= BUDGET_MAX) {
  // Budget épuisé — skip cette tâche
  return [{ json: { ...item, budgetExceeded: true, currentBudget: budget } }];
}

// Préparer les paramètres selon le type
let systemPrompt = '';
let userPrompt = '';

if (item.batchType === 'Contenu') {
  const toneMap = {
    'expert-local': 'Ton professionnel mais accessible, ciblant artisans et commerçants français. Tutoiement.',
    'rentrerdesmandats': 'Ton expert immobilier digital, professionnel, vouvoiement. Cible: agents immobiliers.',
    'studio': 'Ton créatif et tech, présentant des services digitaux. Tutoiement.',
    'blog': 'Ton personnel, partage d\'expérience tech et entrepreneuriat. Tutoiement.',
    'kitrgpd': 'Ton juridique vulgarisé, RGPD simplifié pour PME. Vouvoiement.',
    'clicsimple': 'Ton pédagogique et patient, ciblant seniors débutants en informatique. Vouvoiement.'
  };
  const tone = toneMap[item.projetCible] || 'Ton professionnel en français.';

  systemPrompt = `Tu es un rédacteur web SEO expert francophone. ${tone} Écris du contenu optimisé SEO avec des titres H2/H3, des paragraphes courts, et un appel à l'action en fin d'article. Le contenu doit être original, utile et engageant.`;
  userPrompt = item.nom;
}

return [{ json: { ...item, budgetExceeded: false, currentBudget: budget, systemPrompt, userPrompt } }];

// ============================================================
// AUDIT: Ping tous les webhooks n8n
// ============================================================
const item = $input.first().json;
const webhooks = [
  { name: 'WF1 Bot Telegram', url: 'https://coaching.estarellas.online/webhook/horizons-bot-v2' },
  { name: 'WF3 GCal Lecture', url: 'https://coaching.estarellas.online/webhook/gcal-leo' },
  { name: 'WF4 GCal Écriture', url: 'https://coaching.estarellas.online/webhook/google-calendar-create' }
];

const results = [];
for (const wh of webhooks) {
  try {
    const start = Date.now();
    // On fait un simple HEAD/GET — le webhook retournera probablement une erreur
    // mais un code HTTP confirme que n8n répond
    const resp = await fetch(wh.url, { method: 'GET', signal: AbortSignal.timeout(10000) });
    const latency = Date.now() - start;
    results.push(`✅ ${wh.name}: HTTP ${resp.status} (${latency}ms)`);
  } catch (err) {
    results.push(`❌ ${wh.name}: ${err.message}`);
  }
}

const resultText = `🔍 AUDIT WEBHOOKS — ${new Date().toLocaleDateString('fr-FR')}\n\n${results.join('\n')}`;

return [{ json: { ...item, batchResult: resultText, taskCost: 0 } }];

// ============================================================
// MAINTENANCE: Vérifications VPS (lecture seule)
// ============================================================
const item = $input.first().json;

// En mode n8n, on ne peut pas SSH directement
// On génère un rapport basique depuis ce qu'on peut observer
const now = new Date();
const resultText = `🔧 MAINTENANCE CHECK — ${now.toLocaleDateString('fr-FR')}\n\n` +
  `⚠️ Checks VPS nécessitent accès SSH.\n` +
  `Recommandation: Exécuter manuellement sur le VPS:\n` +
  `  docker ps --format 'table {{.Names}}\t{{.Status}}\t{{.Size}}'\n` +
  `  df -h /\n` +
  `  docker system df\n\n` +
  `📋 Status: rapport partiel — checks manuels recommandés.`;

return [{ json: { ...item, batchResult: resultText, taskCost: 0 } }];

// ============================================================
// PROCESS RESULT — Format + increment budget
// ============================================================
const staticData = $getWorkflowStaticData('global');
const item = $input.first().json;

let batchResult = '';
let taskCost = 0;

if (item.batchType === 'Contenu') {
  // Résultat OpenRouter
  const choices = item.choices || [];
  if (choices.length > 0) {
    batchResult = choices[0].message?.content || 'Erreur: pas de contenu généré';
  } else {
    batchResult = 'Erreur: réponse OpenRouter vide';
  }
  // Estimer le coût (Haiku: ~0.25$/M input, ~1.25$/M output)
  const usage = item.usage || {};
  const inputTokens = usage.prompt_tokens || 500;
  const outputTokens = usage.completion_tokens || 1500;
  taskCost = (inputTokens * 0.00000025 + outputTokens * 0.00000125) * 1.1; // +10% marge
  taskCost = Math.round(taskCost * 10000) / 10000; // Arrondir à 4 décimales
} else {
  // Audit ou Maintenance — résultat déjà formaté en amont
  batchResult = item.batchResult || 'Pas de résultat';
  taskCost = item.taskCost || 0;
}

// Incrémenter le budget
staticData.night_budget = (staticData.night_budget || 0) + taskCost;

// Stocker le résultat pour le rapport final
if (!staticData.night_results) staticData.night_results = [];
staticData.night_results.push({
  nom: item.nom,
  type: item.batchType,
  projet: item.projetCible,
  cost: taskCost,
  success: !batchResult.startsWith('Erreur')
});

return [{ json: {
  pageId: item.pageId,
  batchResult: batchResult.substring(0, 2000), // Limite Notion rich text
  taskCost,
  totalBudget: staticData.night_budget,
  statut: batchResult.startsWith('Erreur') ? '❌ Échec' : '✅ Fait'
}}];

// ============================================================
// BUILD SUMMARY — Rapport nocturne pour Telegram
// ============================================================
const staticData = $getWorkflowStaticData('global');
const results = staticData.night_results || [];
const totalBudget = staticData.night_budget || 0;
const startTime = staticData.night_start || new Date().toISOString();

if (results.length === 0) {
  return [{ json: { chatId: '8572640484', text: '🌙 Batch nocturne : file vide, rien à traiter.', sendReport: false } }];
}

const success = results.filter(r => r.success).length;
const failed = results.filter(r => !r.success).length;

let msg = `🌙 <b>RAPPORT BATCH NOCTURNE</b>\n`;
msg += `📅 ${new Date().toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Europe/Paris' })}\n\n`;

msg += `📊 <b>Résumé :</b>\n`;
msg += `  ✅ Réussies : ${success}\n`;
if (failed > 0) msg += `  ❌ Échouées : ${failed}\n`;
msg += `  💰 Coût total : ${Math.round(totalBudget * 10000) / 10000}€ / 0.30€\n\n`;

msg += `📋 <b>Détail :</b>\n`;
for (const r of results) {
  const icon = r.success ? '✅' : '❌';
  const typeIcon = r.type === 'Contenu' ? '📝' : r.type === 'Audit' ? '🔍' : '🔧';
  msg += `  ${icon} ${typeIcon} ${r.nom.substring(0, 40)}${r.projet ? ' (' + r.projet + ')' : ''}\n`;
}

if (totalBudget >= 0.30) {
  msg += `\n⚠️ Budget nuit atteint (${Math.round(totalBudget * 100) / 100}€). Tâches restantes reportées.`;
}

// Cleanup static data
staticData.night_results = [];
staticData.night_budget = 0;

return [{ json: { chatId: '8572640484', text: msg.slice(0, 4096), parse_mode: 'HTML', sendReport: true } }];

// Budget dépassé — log et continue vers summary
const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');

if (!staticData.night_results) staticData.night_results = [];
staticData.night_results.push({
  nom: item.nom,
  type: item.batchType,
  projet: item.projetCible,
  cost: 0,
  success: false,
  skipped: true
});

return [{ json: item }];
